    def check_if_scrolled_to_top(self):
        # 使用 JavaScript 检查当前滚动位置是否为 0
        script = """
            (function() {
                try {
                    var scrolledToTop = (window.scrollY === 0);
                    return scrolledToTop;
                } catch (e) {
                    console.log(e);
                    return false;
                }
            })();
        """
        self.messageBrowser.page().runJavaScript(script, self.handle_scroll_check_result)

    def handle_scroll_check_result(self, result):
        # 处理 JavaScript 返回的结果
        if result is None:
            print("JavaScript execution returned None. Please check the script for errors.")
        elif result:
            print("The webpage is scrolled to the top.")
        else:
            print("The webpage is not scrolled to the top.")

